BEGIN
  INSERT INTO public.profiles (id, full_name, role)
  VALUES (
    new.id,
    COALESCE(
      NULLIF(new.raw_user_meta_data->>'full_name', ''),
      NULLIF(new.raw_user_meta_data->>'fullName', ''),
      new.email,
      'New User'
    ),
    COALESCE(
      NULLIF(new.raw_user_meta_data->>'role', ''),
      'client'
    )::user_role
  )
  ON CONFLICT (id) DO NOTHING;
  RETURN new;
END;
